const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;
const fromAddress = body.fromAddress || '';
const subject = body.subject || '';
const bodyText = (body.bodyText || '').substring(0, 3000);
const classification = body.classification || {};

if (!tenantId) {
  return [{ json: { valid: false, error: 'tenantId requis' } }];
}

return [{ json: { tenantId, fromAddress, subject, bodyText, classification, valid: true } }];

const email = $('02. Valider').first().json;
const knowledgeRows = $input.all().map(i => i.json);

let knowledgeContext = '';
if (knowledgeRows.length > 0 && knowledgeRows[0].content) {
  knowledgeContext = '\n\nBase de connaissances disponible :\n' + knowledgeRows.map(k => `- ${k.title || 'Info'}: ${k.content}`).join('\n');
}

return [{ json: { ...email, knowledgeContext } }];

const aiResponse = $input.first().json;
let parsed;
try {
  const text = aiResponse.message?.content || aiResponse.text || JSON.stringify(aiResponse);
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  parsed = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch (e) {
  parsed = {};
}

const email = $('02. Valider').first().json;

return [{ json: {
  data: {
    subject: parsed.subject || ('Re: ' + email.subject),
    text: parsed.text || 'Nous avons bien reçu votre message et reviendrons vers vous dans les plus brefs délais.',
    html: parsed.html || ('<p>' + (parsed.text || 'Nous avons bien reçu votre message et reviendrons vers vous dans les plus brefs délais.') + '</p>'),
    confidence: Math.min(1, Math.max(0, Number(parsed.confidence) || 0.6)),
    tokensUsed: Number(parsed.tokensUsed) || 0
  }
} }];
